mapper.select:
SELECT * FROM transit_cache
WHERE from_attraction_id = #{fromAttractionId}
  AND to_attraction_id   = #{toAttractionId}
  AND departure_hour     = #{departureHour}
  AND request_mode       = #{requestMode}

mapper.update:
UPDATE transit_cache
SET duration_minutes  = #{durationMinutes},
    transport_mode    = #{transportMode},
    transfer_count    = #{transferCount},
    fare              = #{fare},
    total_distance_m  = #{totalDistanceM},
    total_walk_m      = #{totalWalkM},
    cached_at         = CURRENT_TIMESTAMP
WHERE from_attraction_id = #{fromAttractionId}
  AND to_attraction_id   = #{toAttractionId}
  AND departure_hour     = #{departureHour}
  AND request_mode       = #{requestMode}
